//refAssemblies: System.Net.Http.dll
using System;
using System.IO;
using System.Net.Http;
using System.Net.Http.Headers;
using System.Text;
using System.Threading.Tasks;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// CustomRconProtocol provider for Palworld - drives the game's built-in REST API (the same transport
// the `palworld` query provider uses), because Palworld's native RCON is non-standard and disabled by
// default. The monitor injects Address/Port/Password/Command; the injected Port is the (disabled)
// native RCON port, so the REST port is parsed from the command line and the admin password from
// PalWorldSettings.ini, exactly like PalworldGameQuery. All awaits are inline (async local functions
// that capture script-scoped locals fail at runtime under the Roslyn scripting host).

string result;
try
{
    string command = (Globals.Variables.Parse<string>("Command") ?? string.Empty).Trim();
    if (string.IsNullOrWhiteSpace(command)) { Globals.ReturnValue = string.Empty; return; }

    string address = Globals.Variables.Parse<string>("Address");
    if (string.IsNullOrEmpty(address)) address = Globals.ThisService.IPAddress;

    // REST API port from the stored command line (-RESTAPIPort=<n>).
    string cmdLine = Globals.ThisService.Commandline ?? string.Empty;
    int restPort = 0;
    const string portKey = "-RESTAPIPort=";
    int pi = cmdLine.IndexOf(portKey, StringComparison.OrdinalIgnoreCase);
    if (pi >= 0)
    {
        int s = pi + portKey.Length, e = s;
        while (e < cmdLine.Length && char.IsDigit(cmdLine[e])) e++;
        int.TryParse(cmdLine.Substring(s, e - s), out restPort);
    }
    if (restPort <= 0)
    {
        Globals.ReturnValue = "[rcon] -RESTAPIPort=<port> not found on the command line (Palworld REST API not enabled).";
        return;
    }

    // Admin password from PalWorldSettings.ini (Windows or Linux config dir).
    string adminPassword = null;
    string root = Globals.ThisService.RootDirectory ?? string.Empty;
    foreach (var osFolder in new[] { "WindowsServer", "LinuxServer" })
    {
        string iniPath = Path.Combine(root, "Pal", "Saved", "Config", osFolder, "PalWorldSettings.ini");
        if (!File.Exists(iniPath)) continue;
        string ini = File.ReadAllText(iniPath);
        const string pwKey = "AdminPassword=\"";
        int ai = ini.IndexOf(pwKey, StringComparison.Ordinal);
        if (ai >= 0)
        {
            int s = ai + pwKey.Length, e = ini.IndexOf('"', s);
            if (e > s) { adminPassword = ini.Substring(s, e - s); break; }
        }
    }
    if (string.IsNullOrEmpty(adminPassword))
    {
        Globals.ReturnValue = "[rcon] AdminPassword is not set in PalWorldSettings.ini.";
        return;
    }

    var http = new HttpClient { Timeout = TimeSpan.FromSeconds(10) };
    http.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue(
        "Basic", Convert.ToBase64String(Encoding.UTF8.GetBytes("admin:" + adminPassword)));
    string baseUrl = "http://" + address + ":" + restPort + "/v1/api";

    int spaceIdx = command.IndexOf(' ');
    string verb = (spaceIdx < 0 ? command : command.Substring(0, spaceIdx)).ToLowerInvariant();
    string rest = spaceIdx < 0 ? string.Empty : command.Substring(spaceIdx + 1).Trim();

    if (verb == "shutdown" || verb == "stop" || verb == "exit" || verb == "quit")
    {
        // Graceful: save the world first, then schedule a shutdown. Accepts "Shutdown <sec> <msg>".
        int waittime = 1;
        string message = "Server is shutting down";
        if (rest.Length > 0)
        {
            int rsp = rest.IndexOf(' ');
            string first = rsp < 0 ? rest : rest.Substring(0, rsp);
            if (int.TryParse(first, out int w)) { waittime = w < 1 ? 1 : w; if (rsp >= 0) message = rest.Substring(rsp + 1).Trim(); }
            else { message = rest; }
        }
        string escMsg = message.Replace("\\", "\\\\").Replace("\"", "\\\"").Replace("\r", " ").Replace("\n", " ");

        using var saveContent = new StringContent(string.Empty, Encoding.UTF8, "application/json");
        using var saveResp = await http.PostAsync(baseUrl + "/save", saveContent);
        string saveBody = (await saveResp.Content.ReadAsStringAsync() ?? string.Empty).Trim();

        using var shutContent = new StringContent("{\"waittime\":" + waittime + ",\"message\":\"" + escMsg + "\"}", Encoding.UTF8, "application/json");
        using var shutResp = await http.PostAsync(baseUrl + "/shutdown", shutContent);
        string shutBody = (await shutResp.Content.ReadAsStringAsync() ?? string.Empty).Trim();

        result = "save -> HTTP " + (int)saveResp.StatusCode + (saveBody.Length == 0 ? "" : " " + saveBody) +
                 " | shutdown(" + waittime + "s) -> HTTP " + (int)shutResp.StatusCode + (shutBody.Length == 0 ? "" : " " + shutBody);
    }
    else if (verb == "forcestop" || verb == "kill" || verb == "doexit" || verb == "save")
    {
        string p = verb == "save" ? "/save" : "/stop";
        using var content = new StringContent(string.Empty, Encoding.UTF8, "application/json");
        using var resp = await http.PostAsync(baseUrl + p, content);
        string body = (await resp.Content.ReadAsStringAsync() ?? string.Empty).Trim();
        result = "HTTP " + (int)resp.StatusCode + (body.Length == 0 ? "" : " " + body);
    }
    else if (verb == "broadcast" || verb == "announce" || verb == "say")
    {
        string escMsg = rest.Replace("\\", "\\\\").Replace("\"", "\\\"").Replace("\r", " ").Replace("\n", " ");
        using var content = new StringContent("{\"message\":\"" + escMsg + "\"}", Encoding.UTF8, "application/json");
        using var resp = await http.PostAsync(baseUrl + "/announce", content);
        string body = (await resp.Content.ReadAsStringAsync() ?? string.Empty).Trim();
        result = "HTTP " + (int)resp.StatusCode + (body.Length == 0 ? "" : " " + body);
    }
    else if (verb == "info" || verb == "players" || verb == "showplayers" || verb == "list" || verb == "metrics" || verb == "settings")
    {
        string p = (verb == "players" || verb == "showplayers" || verb == "list") ? "/players" : "/" + verb;
        using var resp = await http.GetAsync(baseUrl + p);
        result = (await resp.Content.ReadAsStringAsync() ?? string.Empty).Trim();
    }
    else
    {
        result = "[rcon] Unsupported command '" + verb + "'. Supported: Shutdown <sec> <msg>, ForceStop, Save, " +
                 "Broadcast <msg>, Info, ShowPlayers, Metrics, Settings.";
    }
}
catch (Exception ex)
{
    result = "[rcon] error: " + ex.GetType().Name + ": " + ex.Message;
}

Globals.ReturnValue = result;

