using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using TCAdmin.Web.Shared.Models.Enums;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Palworld Curse mod placement.
//
// IMPORTANT EVENT CHANGE: the V2 script ran on BeforeCustomModInstalled and did the zip
// extraction itself (ZipFile/ExtractPath variables). In V3 the dedicated Curse handler
// downloads AND extracts the mod into InstallPath (the provider "mods" folder) BEFORE the
// install event fires, and it tracks every created/moved file under RootDirectory for
// automatic uninstall. So this logic must run on AfterCustomModInstalled (when the files
// actually exist) and only needs to RELOCATE the extracted mod into Palworld's UE4SS layout:
//   *.lua mods  -> Pal/Binaries/<os>/Mods/<ModName>   (and registered in mods.txt)
//   *.pak files -> Pal/Content/Paks/<FolderName>
// V3's file tracking covers the moved files, so we no longer maintain a list of files for
// deletion — CurseModUninstall.dat now only records the mods.txt entries the uninstall script
// must remove. File ownership is fixed automatically by the scripting engine after this runs.
//
// OS folder follows the GAME OS (ThisGame.OperatingSystem), not the host — a Windows game can
// run on Linux (Wine) and vice versa (WSL).

long modId = Globals.Variables.Parse<long>("ModId");
string installPath = Globals.Variables.Parse<string>("InstallPath");
if (string.IsNullOrEmpty(installPath) || !Directory.Exists(installPath))
{
    ScriptConsole.WriteLine($"[err] InstallPath '{installPath}' does not exist; nothing to place.");
    return;
}

string osFolder = ThisGame.OperatingSystem == EOperatingSystem.Windows ? "Win64" : "Linux";
string modsPath = Path.Combine(ThisService.RootDirectory, "Pal", "Binaries", osFolder, "Mods");
string paksPath = Path.Combine(ThisService.RootDirectory, "Pal", "Content", "Paks");
string modsTxt = Path.Combine(modsPath, "mods.txt");

Directory.CreateDirectory(modsPath);
Directory.CreateDirectory(paksPath);

// mods.txt entries (mod folder names) created by this install — persisted for uninstall.
var luaModNames = new List<string>();

// Move every lua-mod folder found under InstallPath into Pal/Binaries/<os>/Mods.
while (true)
{
    DirectoryInfo parentFolder = FindScriptRoot(installPath);
    if (parentFolder == null)
        break;

    AppendLineIfNotExists(modsTxt, $"{parentFolder.Name}: 1");
    luaModNames.Add(parentFolder.Name);

    var modDestination = new DirectoryInfo(Path.Combine(modsPath, parentFolder.Name));
    if (modDestination.Exists)
        modDestination.Delete(true);
    parentFolder.MoveTo(modDestination.FullName);
}

// Move every pak-containing folder found under InstallPath into Pal/Content/Paks.
while (true)
{
    DirectoryInfo parentFolder = FindPakRoot(installPath);
    if (parentFolder == null)
        break;

    var modDestination = new DirectoryInfo(Path.Combine(paksPath, parentFolder.Name));
    if (modDestination.Exists)
        modDestination.Delete(true);
    parentFolder.MoveTo(modDestination.FullName);
}

WriteUninstallData(modId, luaModNames.Count > 0 ? string.Join(";", luaModNames) : null);

ScriptConsole.WriteLine($"Placed Curse mod {modId}: {luaModNames.Count} lua mod(s) registered in mods.txt.");

// Returns the parent of the directory that contains the first *.lua file (the mod folder),
// or null if no lua files remain under the path.
DirectoryInfo FindScriptRoot(string path)
{
    var dirInfo = new DirectoryInfo(path);
    var file = dirInfo.GetFiles("*.lua", SearchOption.AllDirectories).FirstOrDefault();
    return file?.Directory?.Parent;
}

// Returns the directory that contains the first *.pak file, or null if none remain.
DirectoryInfo FindPakRoot(string path)
{
    var dirInfo = new DirectoryInfo(path);
    var file = dirInfo.GetFiles("*.pak", SearchOption.AllDirectories).FirstOrDefault();
    return file?.Directory;
}

void AppendLineIfNotExists(string filePath, string lineToAdd)
{
    if (!File.Exists(filePath))
    {
        File.WriteAllText(filePath, lineToAdd + Environment.NewLine);
        return;
    }

    var lines = File.ReadAllLines(filePath);
    if (!lines.Contains(lineToAdd))
        File.AppendAllText(filePath, lineToAdd + Environment.NewLine);
}

// Mirrors the V2 CurseModUninstall.dat format ("id=data" lines). data == null removes the id.
void WriteUninstallData(long id, string data)
{
    string filePath = Path.Combine(ThisService.RootDirectory, "CurseModUninstall.dat");
    var newLines = new List<string>();

    if (File.Exists(filePath))
    {
        foreach (var line in File.ReadAllLines(filePath))
        {
            if (line.StartsWith(id + "="))
            {
                if (data != null)
                    newLines.Add(id + "=" + data);
            }
            else
            {
                newLines.Add(line);
            }
        }
    }

    if (data != null && !newLines.Any(l => l.StartsWith(id + "=")))
        newLines.Add(id + "=" + data);

    File.WriteAllLines(filePath, newLines, Encoding.UTF8);
}

