using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using TCAdmin.Web.Shared.Models.Enums;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Palworld Curse mod removal — pairs with the AfterCustomModInstalled placement script.
//
// In V3 the dedicated Curse handler already deletes every file it tracked for this mod
// (GameServiceCurseMod.InstalledFiles), including the lua/pak folders the install script
// relocated into the UE4SS layout. So the only bookkeeping left to undo here is the mods.txt
// registration, which V3 knows nothing about. We read the lua-mod names this mod added from
// CurseModUninstall.dat, strip their "<Name>: 1" lines from mods.txt, defensively remove the
// mod folder if it somehow survived, then clear the .dat entry.
//
// OS folder follows the GAME OS (ThisGame.OperatingSystem), matching the install script.

long modId = Globals.Variables.Parse<long>("ModId");

string osFolder = ThisGame.OperatingSystem == EOperatingSystem.Windows ? "Win64" : "Linux";
string modsPath = Path.Combine(ThisService.RootDirectory, "Pal", "Binaries", osFolder, "Mods");
string modsTxt = Path.Combine(modsPath, "mods.txt");

string uninstallData = ReadUninstallData(modId);
if (!string.IsNullOrEmpty(uninstallData))
{
    foreach (var modName in uninstallData.Split(';', StringSplitOptions.RemoveEmptyEntries))
    {
        RemoveLine(modsTxt, $"{modName}: 1");

        var folder = new DirectoryInfo(Path.Combine(modsPath, modName));
        if (folder.Exists)
            folder.Delete(true);
    }
}

WriteUninstallData(modId, null);

ScriptConsole.WriteLine($"Removed Curse mod {modId} from mods.txt.");

void RemoveLine(string filePath, string lineToRemove)
{
    if (!File.Exists(filePath))
        return;

    var lines = File.ReadAllLines(filePath)
        .Where(line => line.Trim() != lineToRemove)
        .ToList();
    File.WriteAllLines(filePath, lines);
}

string ReadUninstallData(long id)
{
    string filePath = Path.Combine(ThisService.RootDirectory, "CurseModUninstall.dat");
    if (!File.Exists(filePath))
        return null;

    foreach (var line in File.ReadAllLines(filePath))
    {
        if (line.StartsWith(id + "="))
            return line.Substring((id + "=").Length);
    }

    return null;
}

// Mirrors the V2 CurseModUninstall.dat format ("id=data" lines). data == null removes the id.
void WriteUninstallData(long id, string data)
{
    string filePath = Path.Combine(ThisService.RootDirectory, "CurseModUninstall.dat");
    if (!File.Exists(filePath) && data == null)
        return;

    var newLines = new List<string>();
    if (File.Exists(filePath))
    {
        foreach (var line in File.ReadAllLines(filePath))
        {
            if (line.StartsWith(id + "="))
            {
                if (data != null)
                    newLines.Add(id + "=" + data);
            }
            else
            {
                newLines.Add(line);
            }
        }
    }

    if (data != null && !newLines.Any(l => l.StartsWith(id + "=")))
        newLines.Add(id + "=" + data);

    File.WriteAllLines(filePath, newLines, Encoding.UTF8);
}

using System;
using System.IO;
using System.Text.RegularExpressions;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Palworld writes no log file of its own (console-only). With ConsoleWrapper the monitor persists
// the live console to <root>/.tca/console.log, but the Logs tab excludes .tca. On stop, move that
// capture into Pal/Saved/Logs as a dated, ANSI-stripped file so it shows in the Logs tab.
// Windows (Master-hosted) only. The Linux node uses a Batch sibling (script 560) because the C#
// engine's CSharpGameGlobals isn't available on the remote hosting node.
var root = Globals.ThisService.RootDirectory;
var src = Path.Combine(root, ".tca", "console.log");
if (File.Exists(src))
{
    var logsDir = Path.Combine(root, "Pal", "Saved", "Logs");
    Directory.CreateDirectory(logsDir);
    var stamp = DateTime.Now.ToString("yyyy-MM-dd_HH-mm-ss");
    var dst = Path.Combine(logsDir, "console-" + stamp + ".log");
    var text = File.ReadAllText(src);
    var esc = ((char)27).ToString();
    text = Regex.Replace(text, esc + "\\[[0-9;?]*[ -/]*[@-~]", "");
    File.WriteAllText(dst, text);
    File.Delete(src);
    try { Globals.OperatingSystem.SetFileOwnerAutoDetect(dst); } catch { }
}
